import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Empty / fee-only case
  it.todo("quote with empty item list returns premium 5 (only processing fee)");

  // Single base items - simplest premiums
  it.todo("quote with a single plain sword returns premium 115 (100 base + 10 first insurance + 5 fee)");
  it.todo("quote with a single plain amulet returns premium 71 (60 base + 6 first insurance + 5 fee)");
  it.todo("quote with a single plain staff returns premium 93 (80 base + 8 first insurance + 5 fee)");
  it.todo("quote with a single plain potion returns premium 49 (40 base + 4 first insurance + 5 fee)");

  // Components - individual and block pricing
  it.todo("quote with 2 runes returns premium 60 (50 base + 5 first insurance + 5 fee)");
  it.todo("quote with 3 runes returns premium 71 (60 base block + 6 first insurance + 5 fee)");
  it.todo("quote with 4 runes returns premium 115 (100 base + 10 first insurance + 5 fee)");
  it.todo("quote with 7 runes returns premium 198 (175 base + 18 first insurance + 5 fee, rounded up)");
  it.todo("quote with 2 runes + 1 moonstone returns premium 88 (75 base + 8 first insurance + 5 fee)");
  it.todo("quote with 3 runes + 3 moonstones returns premium 137 (120 base + 12 first insurance + 5 fee)");

  // Item-specific modifiers
  it.todo("newcomer with cursed sword: premium 165");
  it.todo("quote with high-enchantment sword (enchantment 5) adds 30% surcharge to that item");
  it.todo("quote with cursed sword at exactly enchantment 5 applies both surcharges");

  // Policy-wide modifiers
  it.todo("long-standing customer (>=2 years) receives 20% loyalty discount on policy base");
  it.todo("customer's second contract receives 15% follow-up discount");

  // Multi-item: modifier scope
  it.todo("policy with cursed sword + plain amulet: cursed surcharge applies only to the cursed item's base");

  // Integration
  it.todo("long-standing customer second contract with cursed enchanted sword: premium 160");

  // Rounding
  it.todo("premium calculation rounded up in MHPCO's favor (197.5 -> 198)");

  // Claims - standard reimbursement
  it.todo("claim on plain sword with damage 500: payout 400 (damage - 100 deductible)");
  it.todo("claim on rune with damage 200: payout 100 (200 - 100 deductible)");

  // Claims - high enchantment clause
  it.todo("claim on steel sword enchantment 9 with damage 1000: payout 400 (50% then deductible)");

  // Claims - dragon material
  it.todo("claim on dragon-material sword enchantment 5 damage 800: payout 700 (full minus deductible)");
  it.todo("claim on dragon-material sword enchantment 9 damage 1000: payout 400 (50% wins, then deductible)");
  it.todo("claim on dragon-material sword exactly enchantment 8 damage 1000: payout 400");

  // Claims - per-item deductible
  it.todo("claim with two damaged items (sword 500 + amulet 300): payout 600 (deductible per item)");

  // Cap behavior
  it.todo("cap is twice the insurance sum based on unmodified insurance values");
  it.todo("successive claims drain the cap; subsequent payouts limited to remaining cap");
  it.todo("payout rounding: 350.5 -> 350 (rounded down in MHPCO's favor)");

  // Multiple items of same type
  it.todo("policy with two swords has insurance sum 2000 and cap 4000; damages to each tracked separately");

  // Block discount does not raise insurance sum
  it.todo("policy with sword + 3 runes has insurance sum 1750 (block affects premium only)");

  // Validation / error handling
  it.todo("quote with unknown item type causes CLI to exit non-zero with stderr");
  it.todo("claim referencing an item not in the policy causes CLI to exit non-zero with stderr");
  it.todo("claim with negative damage amount causes CLI to exit non-zero with stderr");
  it.todo("claim damages array with more entries of a type than insured causes CLI to exit non-zero");
});

