input.content:
type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

const PROCESSING_FEE = 5;
const BASE_PREMIUM: Record<string, number> = { sword: 100 };
const FIRST_INSURANCE_RATE = 0.1;

const itemPremium = (item: Item): number => {
  const base = BASE_PREMIUM[item.type] ?? 0;
  return base + base * FIRST_INSURANCE_RATE;
};

const quotePremium = (items: Item[]): number => {
  const total = items.reduce((sum, item) => sum + itemPremium(item), 0);
  return Math.ceil(total + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

